// function desc : 화면로딩시 
//-------------------------------------------------------------------------  
scwin.onpageload = function() {
    ds_etcCreditInfo.insertRow(0);
	ds_etcCreditInfo.setRowPosition(0);
    lc_tmnYn.setValue("0");
}

scwin.onUdcCompleted = function() {
    if(scwin.pldgNo != ""){
        scwin.setPldgNo(scwin.pldgNo);
        ds_etcCreditInfo.setCellData(0,"pldgNo", scwin.pldgNo);
    }
    // $c.util.setTimeout(function() {
    //         $c.gus.cfDisableObjects([ica_regDtm, ed_crn, ed_busiNm, ed_regDept, ed_regDeptNm, ed_regId, ed_empNm]);
    //     }, {"delay":200});  
    $c.gus.cfDisableObjects([ica_regDtm, ed_crn, ed_busiNm, ed_regDept, ed_regDeptNm, ed_regId, ed_empNm]);
}


scwin.setPldgNo = function(pldgNo)
{   
    ds_etcCreditInfo.setCellData(0,"pldgNo", pldgNo);
    dma_etcCreditInfoSearch.set("pldgNo", pldgNo);

    //alert(hid_pldgNo.getValue());
    sbm_retrieve.action ="/ac.fm.acctrecvmgnt.crdtmgnt.RetrieveEtcCreditListCMD.do";
    $c.sbm.execute(sbm_retrieve);
}

